Actionscript.script:
onClipEvent(load){
   gotoAndStop(_root.性别);
   tmp_aaa = _root.根据物品名查找属性(_root.头部装备,14);
   if(tmp_aaa[0] == true)
   {
      this.发型 = "";
   }
   else
   {
      this.发型 = _root.发型;
   }
   面具 = _root.根据物品名查找属性(_root.头部装备,15);
   身体 = _root.性别 + _root.根据物品名查找属性(_root.上装装备,15) + "身体";
   上臂 = _root.性别 + _root.根据物品名查找属性(_root.上装装备,15) + "上臂";
   左下臂 = _root.性别 + _root.根据物品名查找属性(_root.上装装备,15) + "左下臂";
   右下臂 = _root.性别 + _root.根据物品名查找属性(_root.上装装备,15) + "右下臂";
   左手 = _root.根据物品名查找属性(_root.手部装备,15) + "左手";
   右手 = _root.根据物品名查找属性(_root.手部装备,15) + "右手";
   屁股 = _root.性别 + _root.根据物品名查找属性(_root.下装装备,15) + "屁股";
   左大腿 = _root.性别 + _root.根据物品名查找属性(_root.下装装备,15) + "左大腿";
   右大腿 = _root.性别 + _root.根据物品名查找属性(_root.下装装备,15) + "右大腿";
   小腿 = _root.性别 + _root.根据物品名查找属性(_root.下装装备,15) + "小腿";
   脚 = _root.根据物品名查找属性(_root.脚部装备,15);
   刀 = _root.根据物品名查找属性(_root.刀,15);
   长枪 = _root.根据物品名查找属性(_root.长枪,15);
   手枪 = _root.根据物品名查找属性(_root.手枪,15);
   手枪2 = _root.根据物品名查找属性(_root.手枪2,15);
   _parent.aa.text = _parent._parent.人物表情;
   this.man.头.头.基本款.gotoAndStop(_parent._parent.人物表情);
}
onClipEvent(enterFrame){
   _parent._parent.人物称号 = _root.玩家称号;
   if(_parent._parent.人物称号 == undefined)
   {
      _parent._parent.人物称号 = "菜鸟";
   }
}
